import sys


def solution(n, p, k):
    if n < 1 or n > 100:
        return
    if k < 1 or k > n:
        return
    if p < 1 or p > n:
        return
    if p > k:
        print('<< ', end='')
    for i in range(k):
        if (p - i - 1 > 0):
            print(p - i - 1, end=' ')
    print('(' + str(p) + ') ', end='')
    for i in range(k):
        if (p + i + 1 <= n):
            print(p + i + 1, end=' ')
    if p < n - k:
        print('>>')


n, p, k = map(int, input().split())
solution(n, p, k)
